# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

from rediscluster import RedisCluster
from cryptography.fernet import Fernet

# Redis cluster configuration
REDIS_NODES = [
    {"host": "node1.example.com", "port": 6379},
    {"host": "node2.example.com", "port": 6379},
    {"host": "node3.example.com", "port": 6379},
]

# Secret key for encryption
SECRET_KEY = b'your_secret_key'

# Initialize Redis cluster
redis_cluster = RedisCluster(startup_nodes=REDIS_NODES)

# Initialize Fernet cipher
cipher = Fernet(SECRET_KEY)

def set_sensitive_data(user_id, session_token, api_key):
    # Encrypt sensitive data
    encrypted_session_token = cipher.encrypt(session_token.encode()).decode()
    encrypted_api_key = cipher.encrypt(api_key.encode()).decode()

    # Set data in Redis with TTL
    redis_cluster.setex(f"user_{user_id}_session_token", 3600, encrypted_session_token)
    redis_cluster.setex(f"user_{user_id}_api_key", 604800, encrypted_api_key)

def get_sensitive_data(user_id):
    # Get encrypted data from Redis
    encrypted_session_token = redis_cluster.get(f"user_{user_id}_session_token")
    encrypted_api_key = redis_cluster.get(f"user_{user_id}_api_key")

    # Decrypt sensitive data
    decrypted_session_token = cipher.decrypt(encrypted_session_token.encode()).decode()
    decrypted_api_key = cipher.decrypt(encrypted_api_key.encode()).decode()

    return decrypted_session_token, decrypted_api_key